-- Ghana Tertiary UniConnect Dataset - part 14
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'jayee_health_sciences_public_health', u.id, f.id, 'Public Health' from public.universities u join public.faculties f on f.source_id = 'jayee_health_sciences' where u.source_id = 'jayee' and not exists (select 1 from public.departments where source_id = 'jayee_health_sciences_public_health' or (university_id = u.id and name = 'Public Health'));
update public.departments set source_id = coalesce(source_id, 'jayee_health_sciences_public_health'), faculty_id = (select id from public.faculties where source_id = 'jayee_health_sciences') where source_id = 'jayee_health_sciences_public_health' or (name = 'Public Health' and university_id = (select id from public.universities where source_id = 'jayee'));
