update public.departments set source_id = coalesce(source_id, 'aucb_business_and_management_studies_accounting'), faculty_id = (select id from public.faculties where source_id = 'aucb_business_and_management_studies') where source_id = 'aucb_business_and_management_studies_accounting' or (name = 'Accounting' and university_id = (select id from public.universities where source_id = 'aucb'));
